solution_code:
#include <iostream>

class Vehicle {
public:
    virtual ~Vehicle() = default;
};

class Car : public Vehicle {
public:
    int doors_ = 4;
};

class Truck : public Vehicle {
public:
    int payload_ = 800;
};

void inspect(Vehicle* v) {
    if (Car* c = dynamic_cast<Car*>(v)) {
        std::cout << "Car: " << c->doors_ << " doors\n";
    } else if (Truck* t = dynamic_cast<Truck*>(v)) {
        std::cout << "Truck: " << t->payload_ << " kg\n";
    }
}

int main() {
    Car car;
    Truck truck;
    inspect(&car);
    inspect(&truck);
    return 0;
}

