solution_code:
#include <iostream>

class Animal {
public:
    virtual ~Animal() = default;
};

class Dog : public Animal {};
class Cat : public Animal {};

std::string castResult(Animal* a) {
    if (dynamic_cast<Dog*>(a)) return "success";
    return "fail";
}

int main() {
    int t;
    std::cin >> t;
    if (t == 1) {
        Dog d;
        std::cout << castResult(&d) << "\n";
    } else {
        Cat c;
        std::cout << castResult(&c) << "\n";
    }
    return 0;
}
